sql:
SELECT name, type_1, type_2, base_experience
FROM pokemon
WHERE is_legendary = 1 OR is_mythical = 1;

SELECT name, base_experience
FROM pokemon
ORDER BY base_experience DESC;

SELECT trend_type, SUM(CAST(trend_value AS REAL)) AS total_trend_value
FROM trends
GROUP BY trend_type;

SELECT name, AVG(base_experience) AS avg_base_experience
FROM pokemon
GROUP BY name;

external_knowledge:
- 'Original region' corresponds to region_id = 1;
- 'Classic format' refers to format_id = 1;
- 'Most popular choice' means the highest usage count.

sql:
SELECT pokemon_id, rank, percent
FROM usage_statistics
WHERE rank <= 10;

SELECT rank
FROM usage_statistics
WHERE date = (SELECT MAX(date) FROM usage_statistics);

SELECT pokemon_id, count
FROM usage_statistics
ORDER BY count DESC;

SELECT format_id, SUM(total_battles) AS total_battles
FROM usage_statistics
GROUP BY format_id;

external_knowledge:
- 'Mythical creatures' in this context refers to legendary Pokémon.; 
- 'Singles arena' refers to the competitive format named 'Singles'.;
- 'Throughout the year 2022' indicates the time frame from January 1, 2022, to December 31, 2022.;
